 */
std::vector<CourseStats> query_course_enrollment_stats() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn) {
    return {};
  }

  // Create Course and Enrollment tables
  auto result = conn
    .and_then(create_table<Course> | if_not_exists)
    .and_then(create_table<Enrollment> | if_not_exists);

  if (!result) {
    return {};
  }

  // Query enrollment statistics per course
  auto query_result = result
    .and_then([](auto&& conn) {
      // Build the query using sqlgen DSL
      auto query = select(
        column<&Course::title>(),
        count(column<&Enrollment::enrollment_id>()).as("student_count"),
        avg(column<&Enrollment::grade>()).as("avg_grade")
      ).from<Course>()
       .left_join<Enrollment>(on(column<&Course::course_id>() == column<&Enrollment::course_id>()))
       .group_by(column<&Course::course_id>(), column<&Course::title>());

      return query(conn).and_then(read<std::vector<CourseStats>>);
    });

  if (query_result) {
    return query_result.value();
  }

  return {};
}

}  // namespace query_course_enrollment_stats
