#pragma once

#include <ranges>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace query_daily_traffic_metrics {

struct PageVisit {
  sqlgen::PrimaryKey<int> visit_id;
  std::string url;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> visit_time;
};

struct DailyTraffic {
  std::string visit_date;
  int total_visits;
  int unique_pages;
};

struct DailyTrafficView {
  static constexpr const char* tablename = "DailyTrafficView";
  static constexpr bool is_view = true;
  std::string visit_date;
  int total_visits;
  int unique_pages;
};

/**
 * Function: Calculate daily traffic metrics from a log table.
 * 
 * @return List of daily traffic metrics
 */
std::vector<DailyTraffic> query_daily_traffic_metrics() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to SQLite database
  auto db = sqlite::Database::open("test_db.sqlite");

  // Use the view approach with sqlgen to execute the query
  auto results = db.select<DailyTrafficView>()
    .columns(
      sqlgen::strftime("%Y-%m-%d", &PageVisit::visit_time).as("visit_date"),
      sqlgen::count(&PageVisit::visit_id).as("total_visits"),
      sqlgen::count(sqlgen::distinct(&PageVisit::url)).as("unique_pages")
    )
    .from<PageVisit>()
    .group_by(sqlgen::strftime("%Y-%m-%d", &PageVisit::visit_time))
    .order_by("visit_date")
    .execute();

  // Convert DailyTrafficView results to DailyTraffic
  std::vector<DailyTraffic> daily_metrics;
  daily_metrics.reserve(results.size());

  for (const auto& view_result : results) {
    daily_metrics.push_back(DailyTraffic{
      .visit_date = view_result.visit_date,
      .total_visits = view_result.total_visits,
      .unique_pages = view_result.unique_pages
    });
  }

  return daily_metrics;
}

}  // namespace query_daily_traffic_metrics
```

