namespace query_employee_hierarchy {

struct Employee {
  sqlgen::PrimaryKey<int> emp_id;
  std::string name;
  std::optional<int> manager_id;
};

struct EmployeeManager {
  std::string employee;
  std::optional<std::string> manager;
};

std::vector<EmployeeManager> query_employee_hierarchy() {
    using namespace sqlgen;
    using namespace sqlgen::literals;

    // Create aliases for the Employee table (e1 for employees, e2 for managers)
    auto e1 = alias<Employee>("e1");
    auto e2 = alias<Employee>("e2");

    // Build the query using sqlgen DSL
    auto query = read<std::vector<EmployeeManager>> |
                 from(e1) |
                 left_join(e2, e1->manager_id == e2->emp_id) |
                 select(e1->name.as("employee"), e2->name.as("manager"));

    // Execute the query against the SQLite database
    return sqlgen::sqlite::read<EmployeeManager>("test_db.sqlite", query);
}

}  // namespace query_employee_hierarchy
