  int product_id;
  int quantity;
  double amount;
};

struct CategoryReport {
  std::string category;
  int total_qty;
  double total_amt;
};

struct ProductSalesReport {
  static constexpr const char* tablename = "ProductSalesReport";
  static constexpr bool is_view = true;
  std::string category;
  int total_qty;
  double total_amt;
};

std::vector<CategoryReport> query_product_sales_report() {
    using namespace sqlgen;
    using namespace sqlgen::literals;

    // Create the database connection
    sqlgen::sqlite::Database db("test_db.sqlite");

    // Build the query using sqlgen's fluent interface
    auto query = read<Product, Sale>
               | join<Sale>(on<Product, Sale>(&Product::product_id, &Sale::product_id))
               | group_by(&Product::category)
               | select(&Product::category, 
                        sum(&Sale::quantity).as("total_qty"), 
                        sum(&Sale::amount).as("total_amt"))
               | having(sum(&Sale::amount) > 5000.0);

    // Execute the query and get results
    auto results = sqlgen::sqlite::query<std::vector<ProductSalesReport>>(db, query);

    // Convert from ProductSalesReport to CategoryReport
    std::vector<CategoryReport> report;
    report.reserve(results.size());

    for (const auto& result : results) {
        report.push_back(CategoryReport{
            .category = result.category,
            .total_qty = result.total_qty,
            .total_amt = result.total_amt
        });
    }

    return report;
}

}  // namespace query_product_sales_report
