#include <vector>

namespace query_search_books_by_criteria {

struct Book {
  sqlgen::PrimaryKey<int> book_id;
  std::string title;
  std::string author;
  int year;
  std::string genre;
  double price;
};

struct BookFilters {
  std::optional<std::string> title_keyword;
  std::optional<int> min_year;
  std::optional<std::string> genre;
  std::optional<double> max_price;
};

/**
 * Function: Search for books based on multiple optional criteria.
 * 
 * @param filters Optional filters for title, year, genre, and price
 * @return List of books matching the criteria
 */
std::vector<Book> query_search_books_by_criteria(const BookFilters& filters) {
    using namespace sqlgen;
    using namespace sqlgen::literals;

    // Start with base query
    auto query = sqlite::connect("test_db.sqlite")
                 .and_then(read<Book>);

    // Apply filters dynamically
    if (filters.title_keyword) {
        query = query.and_then(where("title"_c.like("%" + *filters.title_keyword + "%")));
    }

    if (filters.min_year) {
        query = query.and_then(where("year"_c >= *filters.min_year));
    }

    if (filters.genre) {
        query = query.and_then(where("genre"_c == *filters.genre));
    }

    if (filters.max_price) {
        query = query.and_then(where("price"_c <= *filters.max_price));
    }

    // Execute query and return results
    auto result = query.and_then(collect<std::vector<Book>>);

    if (result) {
        return result.value();
    } else {
        // Return empty vector on error
        return {};
    }
}

}  // namespace query_search_books_by_criteria

