#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  auto result = sqlgen::sqlite::connect("test_db.sqlite")
    .and_then([=](auto conn) {
      // Begin transaction
      return conn.execute("BEGIN TRANSACTION")
        .and_then([=](auto conn) {
          // Check if sender has sufficient funds and deduct
          return conn.execute("UPDATE Account SET balance = balance - ? WHERE account_id = ? AND balance >= ?", 
                            amount, from_account_id, amount)
            .and_then([=](auto conn) {
              // Check if the update was successful (rows affected)
              if (conn.changes() == 0) {
                // Insufficient funds, rollback
                return conn.execute("ROLLBACK")
                  .and_then([](auto conn) {
                    return sqlgen::result::ok(conn);
                  });
              }

              // Add to receiver
              return conn.execute("UPDATE Account SET balance = balance + ? WHERE account_id = ?", 
                                amount, to_account_id)
                .and_then([=](auto conn) {
                  // Check if receiver account exists
                  if (conn.changes() == 0) {
                    // Receiver account not found, rollback
                    return conn.execute("ROLLBACK")
                      .and_then([](auto conn) {
                        return sqlgen::result::ok(conn);
                      });
                  }

                  // Both updates successful, commit
                  return conn.execute("COMMIT")
                    .and_then([](auto conn) {
                      return sqlgen::result::ok(conn);
                    });
                });
            });
        });
    });

  return result.has_value();
}

}  // namespace transaction_transfer_funds
```

