#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace schema_create_view_sales_summary {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string name;
  double price;
  int stock;
};

struct Sale {
  sqlgen::PrimaryKey<int, sqlgen::auto_incr> sale_id;
  int product_id;
  int quantity;
  double amount;
};

struct SalesSummary {
  static constexpr bool is_view = true;
  std::string product_name;
  int total_quantity;
  double total_revenue;
};

/**
 * Function: Create a view SalesSummary that aggregates sales by product.
 * 
 * @return true if view creation succeeds, false otherwise
 */
bool create_view_sales_summary() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database
  auto result = sqlgen::sqlite::connect("test_db.sqlite")
    .and_then([](auto conn) {
      // First drop the view if it exists to ensure clean creation
      return conn.exec("DROP VIEW IF EXISTS SalesSummary");
    })
    .and_then([](auto conn) {
      // Create the view using the reference SQL statement
      return conn.exec(R"(
        CREATE VIEW SalesSummary AS
        SELECT p.name as product_name, SUM(s.quantity) as total_quantity, SUM(s.amount) as total_revenue
        FROM Sale s
        JOIN Product p ON s.product_id = p.product_id
        GROUP BY p.name;
      )");
    });

  // Return true if the operation succeeded, false otherwise
  return static_cast<bool>(result);
}

}  // namespace schema_create_view_sales_summary
