namespace generate_sql_dry_run {

struct A {
  sqlgen::PrimaryKey<int> id;
  std::string name;
};

struct B {
  sqlgen::PrimaryKey<int> id;
  int a_id;
  double score;
};

/**
 * This function demonstrates how to build a conditional SQL query.
 * It joins tables A and B, filtering for records where score > 10 and name contains 'x'.
 * Returns: std::string.
 */
std::string generate_sql_dry_run() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Build complex query with joins, where, order_by, limit
  const auto query = sqlgen::read<std::vector<A>> 
                     | join<B>(on("A.id"_c == "B.a_id"_c))
                     | where("B.score"_c > 10.0 and "A.name"_c.like("%x%"))
                     | order_by("B.score"_c.desc())
                     | limit(100);

  // Generate SQL string for SQLite (dry run)
  const std::string sql = sqlgen::sqlite::to_sql(query);

  // Verify generated SQL contains expected clauses
  // (Note: This is just for demonstration - in real code you might want to add assertions)
  const bool has_select = sql.find("SELECT") != std::string::npos;
  const bool has_join = sql.find("JOIN") != std::string::npos;
  const bool has_where = sql.find("WHERE") != std::string::npos;
  const bool has_order_by = sql.find("ORDER BY") != std::string::npos;
  const bool has_limit = sql.find("LIMIT") != std::string::npos;

  // Return the generated SQL string
  return sql;
}

}  // namespace generate_sql_dry_run

