```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace analyze_temporal_data {

struct Event {
  sqlgen::PrimaryKey<int> event_id;
  std::string event_name;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> start_time;
  std::optional<sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S">> end_time;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct TemporalAnalysis {
  int event_id;
  std::string event_name;
  int start_day;
  int start_month;
  int start_year;
  int start_hour;
  int start_minute;
  int start_second;
  int start_weekday;
  int64_t start_epoch;
  std::optional<double> duration_days;
};

/**
 * @brief Analyze temporal data for a collection of events.
 *
 * Inserts the provided events into a temporary SQLite table, runs a query
 * to extract date/time parts and compute duration, and returns the results
 * as a vector of TemporalAnalysis.
 *
 * @param events Vector of Event records to analyze.
 * @return std::vector<TemporalAnalysis> Analysis results for each event that has an end_time.
 */
std::vector<TemporalAnalysis> analyze_temporal_data(const std::vector<Event>& events) {
  using namespace sqlgen;
  using namespace sqlgen::sqlite;

  // Create a temporary in-memory database
  Connection conn(":memory:");

  // Create the Event table
  conn.execute(to_sql(CreateTable<Event>{}));

  // Insert all events into the table
  if (!events.empty()) {
    conn.execute(to_sql(Insert<Event>{events}));
  }

  // Execute the temporal analysis query
  std::string query = R"(
    SELECT 
      event_id,
      event_name,
      CAST(strftime('%d', start_time) AS INTEGER) as start_day,
      CAST(strftime('%m', start_time) AS INTEGER) as start_month,
      CAST(strftime('%Y', start_time) AS INTEGER) as start_year,
      CAST(strftime('%H', start_time) AS INTEGER) as start_hour,
      CAST(strftime('%M', start_time) AS INTEGER) as start_minute,
      CAST(strftime('%S', start_time) AS INTEGER) as start_second,
      CAST(strftime('%w', start_time) AS INTEGER) as start_weekday,
      CAST(strftime('%s', start_time) AS INTEGER) as start_epoch,
      CASE 
        WHEN end_time IS NOT NULL THEN 
          JULIANDAY(end_time) - JULIANDAY(start_time)
        ELSE NULL
      END as duration_days
    FROM Event
    WHERE end_time IS NOT NULL;
  )";

  auto result = conn.execute(query);
  std::vector<TemporalAnalysis> analysis_results;

  for (const auto& row : result) {
    TemporalAnalysis ta;
    ta.event_id = row[0].as_int();
    ta.event_name = row[1].as_string();
    ta.start_day = row[2].as_int();
    ta.start_month = row[3].as_int();
    ta.start_year = row[4].as_int();
    ta.start_hour = row[5].as_int();
    ta.start_minute = row[6].as_int();
    ta.start_second = row[7].as_int();
    ta.start_weekday = row[8].as_int();
    ta.start_epoch = row[9].as_int64();

    // Handle optional duration_days
    if (!row[10].is_null()) {
      ta.duration_days = row[10].as_double();
    } else {
      ta.duration_days = std::nullopt;
    }

    analysis_results.push_back(ta);
  }

  return analysis_results;
}

}  // namespace analyze_temporal_data
```

Key implementation details:

1. **Database Connection**: Uses an in-memory SQLite database (`:memory:`) for temporary processing
2. **Table Creation**: Creates the Event table using sqlgen's `CreateTable` functionality
3. **Data Insertion**: Inserts all provided events using sqlgen's `Insert` functionality
4. **Temporal Analysis Query**: Implements the required SQL operations using SQLite's date/time functions:
   - `strftime()` for extracting date components (day, month, year, hour, minute, second)
   - `strftime('%w')` for weekday (0=Sunday, 6=Saturday)
   - `strftime('%s')` for Unix epoch timestamp
   - `JULIANDAY()` for calculating precise day differences
5. **Result Processing**: Converts SQLite result rows to `TemporalAnalysis` structs, handling optional fields appropriately

The implementation follows the reference SQL structure while adapting it to SQLite's specific date/time functions and the sqlgen library's API.

