```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace trim_and_length_validation {

struct UserProfile {
  sqlgen::PrimaryKey<int> user_id;
  std::string name;
  std::string email;
};

struct ValidatedProfile {
  sqlgen::PrimaryKey<int> user_id;
  std::string trimmed_name;
  std::string trimmed_email;
  int name_length;
  int email_length;
};

/**
 * description: trim_and_length_validation.
 * This function demonstrates how to trim whitespace from string columns and validate their lengths using sqlgen read API.
 * It returns a vector of ValidatedProfile structs, where each struct contains the user_id, trimmed_name, trimmed_email, name_length, and email_length.
 * Returns: std::vector<ValidatedProfile>.
 */
std::vector<ValidatedProfile> trim_and_length_validation() {
  // Connect to SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite").value();

  // Read all user profiles from the database
  auto user_profiles = sqlgen::read<std::vector<UserProfile>>(conn).value();

  std::vector<ValidatedProfile> validated_profiles;

  // Process each user profile
  for (const auto& profile : user_profiles) {
    // Trim whitespace from name and email
    std::string trimmed_name = profile.name;
    std::string trimmed_email = profile.email;

    // Remove leading and trailing whitespace
    auto ltrim = [](std::string& s) {
      s.erase(s.begin(), std::find_if(s.begin(), s.end(), [](unsigned char ch) {
        return !std::isspace(ch);
      }));
    };

    auto rtrim = [](std::string& s) {
      s.erase(std::find_if(s.rbegin(), s.rend(), [](unsigned char ch) {
        return !std::isspace(ch);
      }).base(), s.end());
    };

    auto trim = [&](std::string& s) {
      ltrim(s);
      rtrim(s);
    };

    trim(trimmed_name);
    trim(trimmed_email);

    // Create validated profile with trimmed values and lengths
    ValidatedProfile validated_profile{
      .user_id = profile.user_id,
      .trimmed_name = trimmed_name,
      .trimmed_email = trimmed_email,
      .name_length = static_cast<int>(trimmed_name.length()),
      .email_length = static_cast<int>(trimmed_email.length())
    };

    validated_profiles.push_back(validated_profile);
  }

  return validated_profiles;
}

}  // namespace trim_and_length_validation
