namespace calculate_order_metrics {

struct OrderItem {
  sqlgen::PrimaryKey<int> item_id;
  int order_id;
  int product_id;
  double unit_price;
  int quantity;
  std::optional<double> discount_rate;
  std::optional<double> tax_rate;
};

struct OrderMetrics {
  int item_id;
  int order_id;
  int product_id;
  double unit_price;
  int quantity;
  double discount_rate;
  double tax_rate;
  double gross_total;
  double discounted_total;
  double final_total;
  double unit_cost;
  int quantity_group;
  double estimated_profit;
};

/**
 * Calculate per-item order metrics by loading the provided items into a temporary SQLite table
 * and evaluating SQL expressions for totals, discounts, taxes, cost, grouping, and estimated profit.
 * @param items Vector of OrderItem records to analyze.
 * @return std::vector<OrderMetrics> Analysis results for each order item.
 */
std::vector<OrderMetrics> calculate_order_metrics_impl(const std::vector<OrderItem>& items) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn) {
    return {};
  }

  // Create temporary table for OrderItem
  auto result = conn
    .and_then(create_table<OrderItem> | if_not_exists)
    .and_then([&items](auto&& conn) {
      // Insert all items into the table
      for (const auto& item : items) {
        auto insert_result = sqlgen::write(conn, item);
        if (!insert_result) {
          return result_t<std::decay_t<decltype(conn)>>::error(insert_result.error());
        }
      }
      return result_t<std::decay_t<decltype(conn)>>::ok(std::forward<decltype(conn)>(conn));
    })
    .and_then([](auto&& conn) {
      // Execute the comprehensive metrics query
      const auto query = select(
        "item_id"_c, "order_id"_c, "product_id"_c, "unit_price"_c, "quantity"_c,
        coalesce("discount_rate"_c, 0.0).as("discount_rate"),
        coalesce("tax_rate"_c, 0.0).as("tax_rate"),
        ("unit_price"_c * "quantity"_c).as("gross_total"),
        ("unit_price"_c * "quantity"_c * (1 - coalesce("discount_rate"_c, 0.0) / 100.0)).as("discounted_total"),
        ("unit_price"_c * "quantity"_c * (1 - coalesce("discount_rate"_c, 0.0) / 100.0) * 
         (1 + coalesce("tax_rate"_c, 0.0) / 100.0)).as("final_total"),
        ("unit_price"_c * "quantity"_c / "quantity"_c).as("unit_cost"),
        ("quantity"_c % 10).as("quantity_group"),
        ("unit_price"_c * 0.3).as("estimated_profit")
      ).from<OrderItem>();

      return sqlgen::read<std::vector<OrderMetrics>>(conn, query);
    });

  if (result) {
    return result.value();
  }

  return {};
}

}  // namespace calculate_order_metrics
