```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <cassert>

namespace cascade_delete_demo {

struct Parent {
  sqlgen::PrimaryKey<int> parent_id;
  std::string name;
};

struct Child {
  sqlgen::PrimaryKey<int> child_id;
  sqlgen::ForeignKey<int, Parent, "parent_id"> parent_id;
  std::string note;
};

/**
 * Demonstrates cascade delete behavior in SQLite using foreign key constraints.
 * Returns: bool.
 */
bool cascade_delete_demo() {
  // Connect to SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Enable foreign key constraints (required for SQLite)
  conn.execute("PRAGMA foreign_keys = ON");

  // Drop tables if they exist (clean start)
  conn.execute("DROP TABLE IF EXISTS Child");
  conn.execute("DROP TABLE IF EXISTS Parent");

  // Create Parent table
  conn.execute(R"(
    CREATE TABLE Parent (
      parent_id INTEGER PRIMARY KEY,
      name TEXT NOT NULL
    )
  )");

  // Create Child table with foreign key constraint and ON DELETE CASCADE
  conn.execute(R"(
    CREATE TABLE Child (
      child_id INTEGER PRIMARY KEY,
      parent_id INTEGER,
      note TEXT,
      FOREIGN KEY (parent_id) REFERENCES Parent(parent_id) ON DELETE CASCADE
    )
  )");

  // Insert parent record
  Parent parent{1, "Test Parent"};
  conn.insert(parent);

  // Insert child records that reference the parent
  std::vector<Child> children = {
    Child{1, 1, "First child"},
    Child{2, 1, "Second child"},
    Child{3, 1, "Third child"}
  };

  for (const auto& child : children) {
    conn.insert(child);
  }

  // Verify children were inserted correctly
  auto initial_children = conn.select<Child>().where(Child::parent_id == 1).all();
  assert(initial_children.size() == 3 && "Should have 3 children before deletion");

  // Delete the parent record - this should cascade delete the children
  conn.remove<Parent>().where(Parent::parent_id == 1);

  // Verify parent was deleted
  auto remaining_parents = conn.select<Parent>().where(Parent::parent_id == 1).all();
  assert(remaining_parents.empty() && "Parent should be deleted");

  // Verify children were automatically deleted due to cascade
  auto remaining_children = conn.select<Child>().where(Child::parent_id == 1).all();

  // Clean up
  conn.execute("DROP TABLE IF EXISTS Child");
  conn.execute("DROP TABLE IF EXISTS Parent");

  // Return verification result
  return remaining_children.empty();
}

}  // namespace cascade_delete_demo
