Looking at the code fragments and the requirements, I need to implement a function that connects to an SQLite database and performs NULL/IS NOT NULL checks on the optional fields. Here's the complete implementation:

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace column_is_null_checks {

struct Profile {
  sqlgen::PrimaryKey<int> profile_id;
  std::string display_name;
  std::optional<std::string> bio;
  std::optional<std::string> avatar_url;
};

struct Result {
  int profile_id;
  std::string display_name;
};

std::vector<Result> column_is_null_checks() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Query 1: Filter rows where bio IS NULL
  auto null_bio_results = conn | read<std::vector<Profile>> 
                              | where("bio"_c.is_null())
                              | select("profile_id"_c, "display_name"_c)
                              | read<std::vector<Result>>;

  // Query 2: Filter rows where avatar_url IS NOT NULL  
  auto not_null_avatar_results = conn | read<std::vector<Profile>> 
                                     | where("avatar_url"_c.is_not_null())
                                     | select("profile_id"_c, "display_name"_c)
                                     | read<std::vector<Result>>;

  // Combine both result sets
  std::vector<Result> all_results;
  all_results.reserve(null_bio_results.size() + not_null_avatar_results.size());

  all_results.insert(all_results.end(), 
                    null_bio_results.begin(), null_bio_results.end());
  all_results.insert(all_results.end(), 
                    not_null_avatar_results.begin(), not_null_avatar_results.end());

  return all_results;
}

}  // namespace column_is_null_checks
```

