Looking at the code fragments and the requirements, I need to implement a FULL JOIN between suppliers and products using the `sqlgen` library. Since SQLite doesn't natively support FULL JOIN, I'll need to simulate it using a UNION of LEFT JOINs.

Here's the complete implementation:

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace full_join_suppliers_products {

struct Supplier {
  sqlgen::PrimaryKey<int> supplier_id;
  std::string name;
};

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  int supplier_id;
  std::string name;
};

struct SupProd {
  std::string supplier_name;
  std::optional<std::string> product_name;
};

/**
 * Returns a vector of SupProd structs, where each struct contains the name of a supplier and the name of a product, if any.
 */
std::vector<SupProd> full_join_suppliers_products() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn) {
    return {};
  }

  // Since SQLite doesn't support FULL JOIN directly, we simulate it with UNION of LEFT JOINs
  // This gives us all suppliers (with their products) and all products (with their suppliers)
  auto result = conn
                .and_then([](auto&& db) {
                  // First part: Suppliers with their products (LEFT JOIN)
                  auto left_join = select("s.name"_c.as("supplier_name"), 
                                         "p.name"_c.as("product_name"))
                                  .from<Supplier>("s")
                                  .left_join<Product>("p").on("s.supplier_id"_c == "p.supplier_id"_c);

                  // Second part: Products without suppliers (LEFT JOIN where supplier is missing)
                  auto right_join = select("s.name"_c.as("supplier_name"), 
                                          "p.name"_c.as("product_name"))
                                   .from<Product>("p")
                                   .left_join<Supplier>("s").on("p.supplier_id"_c == "s.supplier_id"_c)
                                   .where("s.supplier_id"_c.is_null());

                  // Combine both results using UNION to simulate FULL JOIN
                  return (left_join | union_(right_join)).execute(db);
                })
                .and_then(read<std::vector<SupProd>>);

  if (result) {
    return result.value();
  }

  return {};
}

}  // namespace full_join_suppliers_products
```

