namespace get_top_products {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string product_name;
  std::string category;
  double price;
};

struct Sales {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  sqlgen::Date sale_date;
};

struct TopProduct {
  int product_id;
  std::string product_name;
  std::string category;
  double total_sales;
};

/**
 * Description: This function retrieves the top products based on total sales.
 * Returns: std::vector<TopProduct>.
 */
std::vector<TopProduct> get_top_products(size_t limit_count = 10) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    // Return empty vector if connection fails
    return {};
  }

  auto conn = conn_result.value();

  // Build the query using sqlgen's fluent interface
  auto query = select(
      columns(
          &Product::product_id,
          &Product::product_name, 
          &Product::category,
          sum(&Product::price * &Sales::quantity).as("total_sales")
      ),
      from<Product>(),
      inner_join<Sales>(on(&Product::product_id == &Sales::product_id)),
      group_by(&Product::product_id, &Product::product_name, &Product::category),
      order_by(sum(&Product::price * &Sales::quantity).desc()),
      limit(limit_count)
  );

  // Execute the query and return results
  auto result = conn.and_then(query<std::vector<TopProduct>>(query));

  if (result) {
    return result.value();
  } else {
    // Return empty vector if query execution fails
    return {};
  }
}

}  // namespace get_top_products
