template <rfl::internal::StringLiteral _alias, class QueryType,
          class... FieldTypes>
inline auto select_from(const QueryType& _query, const FieldTypes&... _fields) {
  using FieldsType =
      rfl::Tuple<typename internal::GetColType<FieldTypes>::Type...>;
  return SelectFrom<QueryType, Literal<_alias>, FieldsType>{
      .fields_ =
          FieldsType(internal::GetColType<FieldTypes>::get_value(_fields)...),
      .from_ = _query};
}

template <rfl::internal::StringLiteral _new_name>
auto as() const noexcept {
  return transpilation::As<transpilation::Col<_name, _alias>, _new_name>{
      .val = transpilation::Col<_name, _alias>{}};
}

template <class T>
auto sum(const T& _t) {
  using Type =
      typename transpilation::ToTranspilationType<std::remove_cvref_t<T>>::Type;
  return transpilation::Aggregation<transpilation::AggregationOp::sum, Type>{
      .val = transpilation::to_transpilation_type(_t)};
}

template <class T>
auto weekday(const T& _t) {
  using Type =
      typename transpilation::ToTranspilationType<std::remove_cvref_t<T>>::Type;
  return transpilation::Operation<transpilation::Operator::weekday, Type>{
      .operand1 = transpilation::to_transpilation_type(_t)};
}

template <rfl::internal::StringLiteral _name>
auto count_distinct(const Col<_name>&) {
  return transpilation::Aggregation<transpilation::AggregationOp::count,
                                    transpilation::Col<_name>>{
      .val = transpilation::Col<_name>{}, .distinct = true};
}

template <class... ColTypes>
auto group_by(const ColTypes&...) {
  return GroupBy<ColTypes...>{};
};

