```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace weekday_sales_analysis {

struct Sales {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> sale_time;
};

struct WeekdayStats {
  int weekday;
  int total_quantity;
};

/**
 * Description: This function analyzes sales data to calculate total quantity sold for each weekday.
 * Returns: std::vector<WeekdayStats>.
 */
std::vector<WeekdayStats> weekday_sales_analysis() {
  using namespace sqlgen;
  using namespace sqlgen::sqlite;

  // Connect to SQLite database
  Connection conn("test_db.sqlite");

  // SQL query to extract weekday and aggregate quantities
  const auto query = Select(
      strftime("%w", column<&Sales::sale_time>()).as("weekday"),
      sum(column<&Sales::quantity>()).as("total_quantity")
  ).from<Sales>().group_by("weekday");

  // Execute query and get results
  auto results = conn.execute(query);

  // Convert results to WeekdayStats vector
  std::vector<WeekdayStats> stats;
  for (const auto& row : results) {
    stats.push_back(WeekdayStats{
      .weekday = std::stoi(row["weekday"]),
      .total_quantity = std::stoi(row["total_quantity"])
    });
  }

  return stats;
}

}  // namespace weekday_sales_analysis
```

This implementation:

1. **Connects to the SQLite database** using `sqlgen::sqlite::Connection`
2. **Uses SQLite's `strftime` function** with `%w` format to extract weekday (0-6 where 0=Sunday)
3. **Aggregates quantities** using `sum()` function grouped by weekday
4. **Executes the query** and converts the results to the required `WeekdayStats` struct
5. **Returns the vector** of weekday statistics

The query will return results like:
- Weekday 0 (Sunday): Total quantity sold
- Weekday 1 (Monday): Total quantity sold
- etc.

The function handles the database connection, query execution, and result mapping as specified in the requirements.

