```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace project_time_tracking {

struct Project {
  sqlgen::PrimaryKey<int> project_id;
  std::string name;
};

struct TimeLog {
  sqlgen::PrimaryKey<int> log_id;
  int project_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> start_time;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> end_time;
};

struct TimeMetrics {
  sqlgen::PrimaryKey<int> project_id;
  std::string name;
  int day;
  int month;
  int year;
  int hour;
  int minute;
  int second;
  double duration_days;
};

/**
 * Description: This function tracks time metrics for each project, including day, month, year, hour, minute, second, and duration in days.
 * Returns: std::vector<TimeMetrics>.
 */
std::vector<TimeMetrics> project_time_tracking() {
  // Connect to SQLite database
  sqlgen::sqlite::connection conn("test_db.sqlite");

  // Build the query using sqlgen
  auto query = sqlgen::select(
    sqlgen::columns(
      &Project::project_id,
      &Project::name,
      sqlgen::strftime("%d", &TimeLog::start_time).as("day"),
      sqlgen::strftime("%m", &TimeLog::start_time).as("month"),
      sqlgen::strftime("%Y", &TimeLog::start_time).as("year"),
      sqlgen::strftime("%H", &TimeLog::start_time).as("hour"),
      sqlgen::strftime("%M", &TimeLog::start_time).as("minute"),
      sqlgen::strftime("%S", &TimeLog::start_time).as("second"),
      sqlgen::julianday(&TimeLog::end_time) - sqlgen::julianday(&TimeLog::start_time).as("duration_days")
    ),
    sqlgen::inner_join<Project, TimeLog>(&Project::project_id, &TimeLog::project_id)
  );

  // Execute the query and return results
  return conn.query<TimeMetrics>(query);
}

}  // namespace project_time_tracking
